  SDRBatchRequest? get BATCH_REQUEST => SDRBatchRequest.reader.vTableGetNullable(_bc, _bcOffset, 6);
  SDRBatchRequest? get batchRequest => BATCH_REQUEST;
  SDRBatchResponse? get BATCH_RESPONSE => SDRBatchResponse.reader.vTableGetNullable(_bc, _bcOffset, 8);
  SDRBatchResponse? get batchResponse => BATCH_RESPONSE;
  SDRSingleInput? get SINGLE_INPUT => SDRSingleInput.reader.vTableGetNullable(_bc, _bcOffset, 10);
  SDRSingleInput? get singleInput => SINGLE_INPUT;
  SDRSingleResult? get SINGLE_RESULT => SDRSingleResult.reader.vTableGetNullable(_bc, _bcOffset, 12);
  SDRSingleResult? get singleResult => SINGLE_RESULT;

  @override
  String toString() {
    return 'SDR{CONFIG: ${CONFIG}, batchRequest: ${batchRequest}, batchResponse: ${batchResponse}, singleInput: ${singleInput}, singleResult: ${singleResult}}';
