class SDRObjectBuilder extends fb.ObjectBuilder {
  final SDRSensorConfigObjectBuilder? _CONFIG;
  final SDRBatchRequestObjectBuilder? _BATCH_REQUEST;
  final SDRBatchResponseObjectBuilder? _BATCH_RESPONSE;
  final SDRSingleInputObjectBuilder? _SINGLE_INPUT;
  final SDRSingleResultObjectBuilder? _SINGLE_RESULT;

  SDRObjectBuilder({
    SDRSensorConfigObjectBuilder? CONFIG,
    SDRBatchRequestObjectBuilder? BATCH_REQUEST,
    SDRBatchRequestObjectBuilder? batchRequest,
    SDRBatchResponseObjectBuilder? BATCH_RESPONSE,
    SDRBatchResponseObjectBuilder? batchResponse,
    SDRSingleInputObjectBuilder? SINGLE_INPUT,
    SDRSingleInputObjectBuilder? singleInput,
    SDRSingleResultObjectBuilder? SINGLE_RESULT,
    SDRSingleResultObjectBuilder? singleResult,
  })
      : _CONFIG = CONFIG,
        _BATCH_REQUEST = batchRequest ?? BATCH_REQUEST,
        _BATCH_RESPONSE = batchResponse ?? BATCH_RESPONSE,
        _SINGLE_INPUT = singleInput ?? SINGLE_INPUT,
        _SINGLE_RESULT = singleResult ?? SINGLE_RESULT;

  /// Finish building, and store into the [fbBuilder].
  @override
  int finish(fb.Builder fbBuilder) {
    final int? CONFIGOffset = _CONFIG?.getOrCreateOffset(fbBuilder);
    final int? BATCH_REQUESTOffset = _BATCH_REQUEST?.getOrCreateOffset(fbBuilder);
    final int? BATCH_RESPONSEOffset = _BATCH_RESPONSE?.getOrCreateOffset(fbBuilder);
    final int? SINGLE_INPUTOffset = _SINGLE_INPUT?.getOrCreateOffset(fbBuilder);
    final int? SINGLE_RESULTOffset = _SINGLE_RESULT?.getOrCreateOffset(fbBuilder);
    fbBuilder.startTable(5);
    fbBuilder.addOffset(0, CONFIGOffset);
    fbBuilder.addOffset(1, BATCH_REQUESTOffset);
    fbBuilder.addOffset(2, BATCH_RESPONSEOffset);
    fbBuilder.addOffset(3, SINGLE_INPUTOffset);
    fbBuilder.addOffset(4, SINGLE_RESULTOffset);
    return fbBuilder.endTable();
  }

  /// Convenience method to serialize to byte list.
  @override
  Uint8List toBytes([String? fileIdentifier]) {
    final fbBuilder = fb.Builder(deduplicateTables: false);
    fbBuilder.finish(finish(fbBuilder), fileIdentifier);
    return fbBuilder.buffer;
